import React from "react";
import { PlayerModel } from "@/models/fixtures/PlayerModel";
import { cn } from "@/lib/utils"; // If you use a className merge util
import {
  getPositionStat,
  getSlotColorClasses,
  getSlotShortCode,
} from "./styleUtils";
import { ArrowRightLeft, Crown } from "lucide-react";
import { useIsMobile } from "@/hooks/use-mobile";

// Example props -- adapt as needed
interface PlayerCardProps {
  slotType: string;
  player: PlayerModel;
  round: number;
  isCaptain: boolean;
  isViceCaptain: boolean;
  isSelected: boolean;
  flag: string;
  onCardClick: () => void;
  onSwapClick: () => void;
}

export function PlayerCard({
  slotType,
  player,
  round,
  isCaptain,
  isViceCaptain,
  flag,
  isSelected,
  onCardClick,
  onSwapClick,
}: PlayerCardProps) {
  // e.g., total fantasy points
  const totalPoints =
    (player.points?.[round] ?? 0) + (player.currentMatchPoints ?? 0);

  // e.g., "bg-red-500" or your theme class
  const baseColor = getSlotColorClasses(slotType);

  // e.g., "BAT"
  const shortCode = getSlotShortCode(slotType);

  const mobile = useIsMobile();

  const stats = getPositionStat(player);

  console.log(stats);

  return (
    <div
      onClick={onCardClick}
      className={cn(
        // !isSelected ? "filter blur-sm" : "",
        // 3:4 ratio card, uniform shape
        "relative w-full aspect-[3/4] rounded-md overflow-hidden shadow-md filter",
        "cursor-pointer transition-transform hover:scale-[1.02]",
        isSelected ? "ring-2 ring-white-400 ring-offset-1" : "",
        // Apply a base color from your position-based classes
        baseColor,
      )}
    >
      {(isCaptain || isViceCaptain) && (
        <div
          className="absolute  z-10 flex items-center"
          style={{
            top: mobile ? "6px" : "8px",
            right: mobile ? "6px" : "8px",
          }}
        >
          <div
            className=" rounded-full flex items-center justify-center drop-shadow"
            style={{
              backgroundColor: isCaptain ? "gold" : "silver",
              padding: mobile ? "3px" : "4px",
            }}
          >
            <Crown className="h-4 w-4 md:h-5 md:w-5 text-black" />
          </div>
        </div>
      )}

      {/* (Optional) overlay to help text stand out */}
      <div className="absolute inset-0 bg-black/20" />
      {/*
        TOP HALF (~50% of card height)
        We'll place the points in the center of the left side,
        and the player image straddling the halfway line on the right.
      */}
      <div className="absolute top-0 left-0 w-full h-1/2">
        {/* Diagonal or multi-stop gradient */}
        <div className="absolute inset-0 bg-gradient-to-br from-white/10 via-transparent to-black/40" />

        <div
          className="
              absolute
              inset-0
              filter blur-[5px]

              bg-[url('https://www.heropatterns.com/svg/topography.svg')]
              bg-repeat
              bg-gray-800/20
            "
        />

        <div className="absolute inset-0 bg-black/20" />
        {/* Points: center of the top-left area (half the width, half the height) */}
        <div className="absolute top-0 left-0 w-1/2 h-full flex items-center justify-center">
          <div className="text-white drop-shadow-md flex flex-col text-center items-center space-y-1">
            <div className="flex flex-col text-2xl md:text-3xl font-extrabold">
              {totalPoints}
              <div className="text-xs font-light text-gray-300">Pts.</div>
            </div>
            <div className="text-base"> {player.teamCode} </div>
            <img src={flag} alt="AlT" className="w-4 md:w-6" />
          </div>
        </div>

        {/* Player image: anchored at the halfway mark of the entire card */}
        <img
          src={player.imagePath ?? ""}
          alt={player.playerName}
          style={{
            position: "absolute",
            top: "50%", // anchor near the halfway line
            right: 0, // or left: "50%", etc.—up to you
            transform: mobile ? "translateY(-38%)" : "translateY(-45%)",
            height: mobile ? "80%" : "90%", // 30% of the card's total height
            width: "auto", // auto-calculated width => preserves aspect ratio
            objectFit: "contain",
          }}
        />
      </div>
      {/*
        BOTTOM HALF (~50% of card height)
        Name + Swap button
      */}
      <div className="absolute bottom-0 left-0 w-full h-1/2 flex flex-col items-center p-2 space-y-2">
        {/* Player Name */}
        <p className="text-sm md:text-lg text-white font-bold drop-shadow-md text-center line-clamp-2">
          {player.playerName}
        </p>

        <div className="flex flex-col items-center w-full px-2 space-y-1">
          <div className="flex justify-between w-full text-xs text-white/80">
            {/* Main Stat */}
            <div className="flex flex-col items-center flex-1">
              <span className="text-2xs md:text-xs uppercase tracking-wide">
                {stats.label}
              </span>
              <span className="text-xs md:text-sm font-bold text-white">
                {stats.value}
              </span>
            </div>

            {/* Vertical Separator - Only show if secondary stat exists */}
            {!mobile && <div className="h-full w-px bg-white/20 mx-2" />}

            {/* Secondary Stat (when space permits) */}
            {!mobile && (
              <div className="flex flex-col items-center flex-1">
                <span className="text-2xs md:text-xs uppercase tracking-wide">
                  {stats.secondary}
                </span>
                <span className="text-xs md:text-sm font-bold text-white">
                  {stats.secondaryValue}
                </span>
              </div>
            )}
          </div>
        </div>

        {/* Role Pill + Swap Button Container */}
        <div className="absolute bottom-0 left-0 w-full flex items-center justify-between px-2 pb-2">
          {/* Role Pill */}
          <div
            className={cn(
              "px-3 py-1 rounded-full text-xs font-bold uppercase tracking-wide",
              "text-white shadow-sm border border-white/20",
              baseColor,
            )}
          >
            {shortCode} {/* Add a function to get full position name */}
          </div>

          {/* Swap Button */}
          <button
            onClick={(e) => {
              e.stopPropagation();
              onSwapClick();
            }}
            className={cn(
              "flex items-center justify-center p-2 rounded-full shadow-sm",
              "transition-all transform hover:scale-110",
              "bg-white/20 hover:bg-white/30 border border-white/30",
              "text-white hover:text-white",
              !player.editable && "opacity-50 cursor-not-allowed",
            )}
            disabled={!player.editable}
          >
            <ArrowRightLeft className="h-4 w-4" />{" "}
            {/* Add your swap icon component */}
          </button>
        </div>
      </div>
    </div>
  );
}
